311:   const parseShareIdFromTunnelName = (tunnelName: string): number | null => {
312:     const normalized = (tunnelName || "").trim();
313: 
314:     if (!normalized.startsWith("Share-")) {
315:       return null;
316:     }
317: 
318:     const raw = normalized.slice("Share-".length);
319:     const idx = raw.indexOf("-Port-");
320: 
321:     if (idx <= 0) {
322:       return null;
323:     }
324: 
325:     const shareId = Number(raw.slice(0, idx).trim());
326: 
327:     return Number.isFinite(shareId) && shareId > 0 ? shareId : null;
328:   };
