330:   const mergeFederationShareFlow = async (
331:     forwardsData: Forward[],
332:   ): Promise<Forward[]> => {
333:     if (forwardsData.length === 0) {
334:       return forwardsData;
335:     }
336: 
337:     try {
338:       const [usageRes, localShareRes] = await Promise.all([
339:         getPeerRemoteUsageList(),
340:         getPeerShareList(),
341:       ]);
342: 
343:       const flowByShare = new Map<number, number>();
344:       const shareIdsByTunnel = new Map<number, Set<number>>();
345: 
346:       if (usageRes.code === 0 && Array.isArray(usageRes.data)) {
347:         usageRes.data.forEach((item: Record<string, unknown>) => {
348:           const shareId = Number(item.shareId || 0);
349:           const currentFlow = Number(item.currentFlow || 0);
350: 
351:           if (
352:             Number.isFinite(shareId) &&
353:             shareId > 0 &&
354:             Number.isFinite(currentFlow) &&
355:             currentFlow > 0
356:           ) {
357:             const prev = flowByShare.get(shareId) || 0;
358: 
359:             flowByShare.set(shareId, Math.max(prev, currentFlow));
360:           }
361: 
362:           if (Number.isFinite(shareId) && shareId > 0) {
363:             const bindings = Array.isArray(item.bindings)
364:               ? (item.bindings as Array<Record<string, unknown>>)
365:               : [];
366: 
367:             bindings.forEach((binding) => {
368:               const tunnelId = Number(binding.tunnelId || 0);
369:               const chainType = Number(binding.chainType || 0);
370: 
371:               if (!Number.isFinite(tunnelId) || tunnelId <= 0) {
372:                 return;
373:               }
374: 
375:               if (Number.isFinite(chainType) && chainType !== 1) {
376:                 return;
377:               }
378: 
379:               let shareSet = shareIdsByTunnel.get(tunnelId);
380: 
381:               if (!shareSet) {
382:                 shareSet = new Set<number>();
383:                 shareIdsByTunnel.set(tunnelId, shareSet);
384:               }
385: 
386:               shareSet.add(shareId);
387:             });
388:           }
389:         });
390:       }
391: 
392:       if (localShareRes.code === 0 && Array.isArray(localShareRes.data)) {
393:         localShareRes.data.forEach((item: Record<string, unknown>) => {
394:           const shareId = Number(item.id || 0);
395:           const currentFlow = Number(item.currentFlow || 0);
396: 
397:           if (
398:             Number.isFinite(shareId) &&
399:             shareId > 0 &&
400:             Number.isFinite(currentFlow) &&
401:             currentFlow > 0
402:           ) {
403:             const prev = flowByShare.get(shareId) || 0;
404: 
405:             flowByShare.set(shareId, Math.max(prev, currentFlow));
406:           }
407:         });
408:       }
409: 
410:       if (flowByShare.size === 0) {
411:         return forwardsData;
412:       }
413: 
414:       const resolveShareIdForForward = (forward: Forward): number | null => {
415:         const candidates = new Set<number>();
416:         const shareIdFromName = parseShareIdFromTunnelName(
417:           forward.tunnelName || "",
418:         );
419: 
420:         if (shareIdFromName) {
421:           candidates.add(shareIdFromName);
422:         }
423: 
424:         const tunnelId = Number(forward.tunnelId || 0);
425:         const shareSetByTunnel = shareIdsByTunnel.get(tunnelId);
426: 
427:         if (shareSetByTunnel && shareSetByTunnel.size > 0) {
428:           shareSetByTunnel.forEach((shareId) => {
429:             if (Number.isFinite(shareId) && shareId > 0) {
430:               candidates.add(shareId);
431:             }
432:           });
433:         }
434: 
435:         if (candidates.size === 0) {
436:           return null;
437:         }
438: 
439:         let bestShareId: number | null = null;
440:         let bestFlow = 0;
441: 
442:         candidates.forEach((shareId) => {
443:           const shareFlow = flowByShare.get(shareId) || 0;
444: 
445:           if (shareFlow > bestFlow) {
446:             bestFlow = shareFlow;
447:             bestShareId = shareId;
448:           }
449:         });
450: 
451:         return bestShareId;
452:       };
453: 
454:       const resolvedShareByForwardId = new Map<number, number>();
455: 
456:       forwardsData.forEach((forward) => {
457:         const shareId = resolveShareIdForForward(forward);
458: 
459:         if (shareId) {
460:           resolvedShareByForwardId.set(forward.id, shareId);
461:         }
462:       });
463: 
464:       const forwardCountByShare = new Map<number, number>();
465: 
466:       forwardsData.forEach((forward) => {
467:         const shareId = resolvedShareByForwardId.get(forward.id) || null;
468: 
469:         if (!shareId || !flowByShare.has(shareId)) {
470:           return;
471:         }
472: 
473:         forwardCountByShare.set(
474:           shareId,
475:           (forwardCountByShare.get(shareId) || 0) + 1,
476:         );
477:       });
478: 
479:       return forwardsData.map((forward) => {
480:         const shareId = resolvedShareByForwardId.get(forward.id) || null;
481: 
482:         if (!shareId) {
483:           return { ...forward, federationShareFlow: undefined };
484:         }
485: 
486:         const shareFlow = flowByShare.get(shareId) || 0;
487: 
488:         if (shareFlow <= 0) {
489:           return { ...forward, federationShareFlow: undefined };
490:         }
491: 
492:         const directFlow = (forward.inFlow || 0) + (forward.outFlow || 0);
493: 
494:         if (directFlow > 0) {
495:           return { ...forward, federationShareFlow: undefined };
496:         }
497: 
498:         const count = forwardCountByShare.get(shareId) || 1;
499:         const estimated = Math.max(1, Math.floor(shareFlow / count));
500: 
501:         return { ...forward, federationShareFlow: estimated };
502:       });
503:     } catch {
504:       return forwardsData;
505:     }
506:   };
