]map[string]interface{}, 0, len(workItems))\n68: \tfor _, workItem := range workItems {\n69: \t\ttargetIP := strings.TrimSpace(workItem.targetIP)\n70: \t\ttargetPort := workItem.targetPort\n71: \t\tif workItem.hasChainHop {\n72: \t\t\tfromNode, _ := h.cachedNode(nodeCache, workItem.fromNodeID)\n73: \t\t\ttargetNode, err := h.cachedNode(nodeCache, workItem.toNode.NodeID)\n74: \t\t\tif err == nil {\n75: \t\t\t\tresolvedIP, resolvedPort, resolveErr := resolveChainProbeTarget(fromNode, targetNode, workItem.toNode.Port, workItem.ipPreference)\n76: \t\t\t\tif resolveErr == nil {\n77: \t\t\t\t\ttargetIP = resolvedIP\n78: \t\t\t\t\ttargetPort = resolvedPort\n79: \t\t\t\t}\n80: \t\t\t}\n81: \t\t}\n82: \t\tif targetPort <= 0 {\n83: \t\t\ttargetPort = 443\n84: \t\t}\n85: \n86: \t\tnodeName := fmt.Sprintf(\"node_%d\", workItem.fromNodeID)\n87: \t\tif node, err := h.cachedNode(nodeCache, workItem.fromNodeID); err == nil && strings.TrimSpace(node.Name) != \"\" {\n88: \t\t\tnodeName = node.Name\n89: \t\t}\n90: \n91: \t\titem := map[string]interface{}{\n92: \t\t\t\"success\":     false,\n93: \t\t\t\"diagnosing\":  true,\n94: \t\t\t\"description\": workItem.description,\n95: \t\t\t\"nodeName\":    nodeName,\n96: \t\t\t\"nodeId\":      strconv.FormatInt(workItem.fromNodeID, 10),\n97: \t\t\t\"targetIp\":    targetIP,\n98: \t\t\t\"targetPort\":  targetPort,\n99: \t\t\t\"message\":     \"诊断中...\",\n100: \t\t}\n101: \t\tfor key, value := range workItem.metadata {\n102: \t\t\titem[key] = value\n103: \t\t}\n104: \t\titems = append(items, item)\n105: \t}\n106: \n107: \treturn items\n108: }\n109: \n110: const diagnosisMaxConcurrency = 8\n111: \n112: const (\n113: \tdefaultNodeCommandTimeout  = 6 * time.Second\n114: \tdiagnosisCommandTimeout    = 30 * time.Second\n115: \tdiagnosisRequestTimeout    = 2 * time.Minute\n116: \tdiagnosisCommandTimeoutMsg = \"诊断超时（30秒）\"\n117: \tdiagnosisRequestTimeoutMsg = \"诊断超时（2分钟）\"\n118: )\n119: \n120: func (h *Handler) resolveForwardAccess(r *http.Request, forwardID int64) (*forwardRecord, int64, int, error) {\n121: \tuserID, roleID, err := userRoleFromRequest(r)\n122: \tif err != nil {\n123: \t\treturn nil, 0, 0, err\n124: \t}\n125: \tforward, err := h.ensureForwardAccessByActor(userID, roleID, forwardID)\n126: \tif err != nil {\n127: \t\treturn nil, userID, roleID, err\n128: \t}\n129: \treturn forward, userID, roleID, nil\n130: }\n131: \n132: func (h *Handler) ensureForwardAccessByActor(actorUserID int64, actorRole int, forwardID int64) (*forwardRecord, error) {\n133: \tforward, err := h.getForwardRecord(forwardID)\n134: \tif err != nil {\n135: \t\treturn nil, err\n136: \t}\n137: \tif actorRole != 0 && forward.UserID != actorUserID {\n138: \t\treturn nil, errForwardNotFound\n139: \t}\n140: \treturn forward, nil\n141: }\n142: \n143: func (h *Handler) ensureTunnelPermission(userID int64, roleID int, tunnelID int64) error {\n144: \tif roleID == 0 {\n145: \t\treturn nil\n146: \t}\n147: \tok, err := h.repo.UserTunnelExistsByUserAndTunnel(userID, tunnelID)\n148: \tif err != nil {\n149: \t\treturn err\n150: \t}\n151: \tif !ok {\n152: \t\treturn errors.New(\"你没有该隧道的权限\")\n153: \t}\n154: \treturn nil\n155: }\n156: \n157: func (h *Handler) getForwardRecord(forwardID int64) (*forwardRecord, error) {\n158: \tfr, err := h.repo.GetForwardRecord(forwardID)\n159: \tif err != nil {\n160: \t\treturn nil, err\n161: \t}\n162: \tif fr == nil {\n163: \t\treturn nil, errForwardNotFound\n164: \t}\n165: \treturn fr, nil\n166: }\n167: \n168: func (h *Handler) getTunnelRecord(tunnelID int64) (*tunnelRecord, error) {\n169: \ttr, err := h.repo.GetTunnelRecord(tunnelID)\n170: \tif err != nil {\n171: \t\treturn nil, err\n172: \t}\n173: \tif tr == nil {\n174: \t\treturn nil, errors.New(\"隧道不存在\")\n175: \t}\n176: \treturn tr, nil\n177: }\n178: \n179: func (h *Handler) listForwardsByTunnel(tunnelID int64) ([]forwardRecord, error) {\n180: \treturn h.repo.ListForwardsByTunnel(tunnelID)\n181: }\n182: \n183: func (h *Handler) listForwardPorts(forwardID int64) ([]forwardPortRecord, error) {\n184: \treturn h.repo.ListForwardPorts(forwardID)\n185: }\n186: \n187: func (h *Handler) isTunnelSelectedTLSProtocol(tunnelID int64) (bool, error) {\n188: \tprotocol, err := h.repo.GetTunnelOutProtocol(tunnelID)\n189: \tif err != nil {\n190: \t\treturn false, err\n191: \t}\n192: \treturn isTLSTunnelProtocol(protocol), nil\n193: }\n194: \n195: func (h *Handler) getNodeRecord(nodeID int64) (*nodeRecord, error) {\n196: \tn, err := h.repo.GetNodeRecord(nodeID)\n197: \tif err != nil {\n198: \t\treturn nil, err\n199: \t}\n200: \tif n == nil {\n201: \t\treturn nil, errors.New(\"节点不存在\")\n202: \t}\n203: \treturn n, nil\n204: }\n205: \n206: func (h *Handler) resolveUserTunnelAndLimiter(userID, tunnelID int64) (int64, *int64, *int, error) {\n207: \tinfo, err := h.repo.ResolveUserTunnelAndLimiter(userID, tunnelID)\n208: \tif err != nil {\n209: \t\treturn 0, nil, nil, err\n210: \t}\n211: \tif info == nil {\n212: \t\treturn 0, nil, nil, nil\n213: \t}\n214: \treturn info.UserTunnelID, info.LimiterID, info.Speed, nil\n215: }\n216: \n217: func (h *Handler) listUserTunnelIDs(userID, tunnelID int64) ([]int64, error) {\n218: \treturn h.repo.ListUserTunnelIDs(userID, tunnelID)\n219: }\n220: \n221: func (h *Handler) listUserTunnelIDsByUser(userID int64) ([]int64, error) {\n222: \treturn h.repo.ListUserTunnelIDsByUser(userID)\n223: }\n224: \n225: func (h *Handler) syncForwardServices(forward *forwardRecord, method string, allowFallbackAdd bool) error {\n226: \tif h == nil || forward == nil {\n227: \t\treturn errors.New(\"invalid forward sync context\")\n228: \t}\n229: \n230: \ttunnel, err := h.getTunnelRecord(forward.TunnelID)\n231: \tif err != nil {\n232: \t\treturn err\n233: \t}\n234: \tports, err := h.listForwardPorts(forward.ID)\n235: \tif err != nil {\n236: \t\treturn err\n237: \t}\n238: \tif len(ports) == 0 {\n239: \t\treturn errors.New(\"转发入口端口不存在\")\n240: \t}\n241: \n242: \t// Determine limiter from forward's SpeedID first, fallback to UserTunnel's limiter\n243: \tvar limiterID *int64\n244: \tvar speed *int\n245: \n246: \tif forward.SpeedID.Valid && forward.SpeedID.Int64 > 0 {\n247: \t\t// Forward has its own speed limit\n248: \t\tspeedVal, err := h.repo.GetSpeedLimitSpeed(forward.SpeedID.Int64)\n249: \t\tif err == nil && speedVal > 0 {\n250: \t\t\tlimiterID = &forward.SpeedID.Int64\n251: \t\t\tspeed = &speedVal\n252: \t\t}\n253: \t}\n254: \n255: \tif limiterID == nil {\n256: \t\t// Fall back to UserTunnel speed limit\n257: \t\tvar utLimiterID *int64\n258: \t\tvar utSpeed *int\n259: \t\t_, utLimiterID, utSpeed, err = h.resolveUserTunnelAndLimiter(forward.UserID, forward.TunnelID)\n260: \t\tif err != nil {\n261: \t\t\treturn err\n262: \t\t}\n263: \t\tlimiterID = utLimiterID\n264: \t\tspeed = utSpeed\n265: \t}\n266: \n267: \tserviceBase := buildForwardServiceBase(forward.ID, forward.UserID, 0)\n268: \ttunnelTLSProtocol, err := h.isTunnelSelectedTLSProtocol(forward.TunnelID)\n269: \tif err != nil {\n270: \t\treturn err\n271: \t}\n272: \n273: \tfor _, fp := range ports {\n274: \t\tif limiterID != nil && speed != nil {\n275: \t\t\tif err := h.ensureLimiterOnNode(fp.NodeID, *limiterID, *speed); err != nil {\n276: \t\t\t\treturn err\n277: \t\t\t}\n278: \t\t}\n279: \n280: \t\tnode, err := h.getNodeRecord(fp.NodeID)\n281: \t\tif err != nil {\n282: \t\t\treturn err\n283: \t\t}\n284: \t\tservices := buildForwardServiceConfigs(serviceBase, forward, tunnel, node, fp.Port, limiterID, tunnelTLSProtocol)\n285: \t\t_, err = h.sendNodeCommand(node.ID, method, services, true, false)\n286: \t\tif err != nil && allowFallbackAdd && method == \"UpdateService\" {\n287: \t\t\t_, err = h.sendNodeCommand(node.ID, \"AddService\", services, true, false)\n288: \t\t}\n289: \t\tif err != nil {\n290: \t\t\treturn fmt.Errorf(\"节点 %s 下发失败: %w\", node.Name, err)\n291: \t\t}\n292: \t}\n293: \treturn nil\n294: }\n295: \n296: func (h *Handler) controlForwardServices(forward *forwardRecord, commandType string, tolerateNotFound bool) error {\n297: \tif h == nil || forward == nil {\n298: \t\treturn errors.New(\"invalid forward control context\")\n299: \t}\n300: \tports, err := h.listForwardPorts(forward.ID)\n301: \tif err != nil {\n302: \t\treturn err\n303: \t}\n304: \tif len(ports) == 0 {\n305: \t\treturn nil\n306: \t}\n307: \tuserTunnelID, _, _, err := h.resolveUserTunnelAndLimiter(forward.UserID, forward.TunnelID)\n308: \tif err != nil {\n309: \t\treturn err\n310: \t}\n311: \tuserTunnelIDs, err := h.listUserTunnelIDs(forward.UserID, forward.TunnelID)\n312: \tif err != nil {\n313: \t\treturn err\n314: \t}\n315: \tallUserTunnelIDs, err := h.listUserTunnelIDsByUser(forward.UserID)\n316: \tif err != nil {\n317: \t\treturn err\n318: \t}\n319: \tcandidateTunnelIDs := make([]int64, 0, len(userTunnelIDs)+len(allUserTunnelIDs))\n320: \tcandidateTunnelIDs = append(candidateTunnelIDs, userTunnelIDs...)\n321: \tcandidateTunnelIDs = append(candidateTunnelIDs, allUserTunnelIDs...)\n322: \tbases := buildForwardServiceBaseCandidates(forward.ID, forward.UserID, userTunnelID, candidateTunnelIDs)\n323: \tseen := map[int64]struct{}{}\n324: \tfor _, fp := range ports {\n325: \t\tif _, ok := seen[fp.NodeID]; ok {\n326: \t\t\tcontinue\n327: \t\t}\n328: \t\tseen[fp.NodeID] = struct{}{}\n329: \n330: \t\tvar lastNotFoundErr error\n331: \t\tnodeHandled := false\n332: \n333: \t\tfor _, base := range bases {\n334: \t\t\tvariants := []string{base + \"_tcp\", base + \"_udp\"}\n335: \t\t\tif shouldTryLegacySingleService(commandType) || strings.EqualFold(strings.TrimSpace(commandType), \"DeleteService\") {\n336: \t\t\t\tvariants = append(variants, base)\n337: \t\t\t}\n338: \n339: \t\t\tcandidateHandled := false\n340: \t\t\tfor _, name := range variants {\n341: \t\t\t\tpayload := map[string]interface{}{\n342: \t\t\t\t\t\"services\": []string{name},\n343: \t\t\t\t}\n344: \t\t\t\t_, err := h.sendNodeCommand(fp.NodeID, commandType, payload, false, false)\n345: \t\t\t\tif err == nil {\n346: \t\t\t\t\tcandidateHandled = true\n347: \t\t\t\t\tcontinue\n348: \t\t\t\t}\n349: \t\t\t\tif !isNotFoundError(err) {\n350: \t\t\t\t\treturn err\n351: \t\t\t\t}\n352: \t\t\t\tlastNotFoundErr = err\n353: \t\t\t}\n354: \n355: \t\t\tif candidateHandled {\n356: \t\t\t\tnodeHandled = true\n357: \t\t\t\tbreak\n358: \t\t\t}\n359: \t\t}\n360: \n361: \t\tif nodeHandled {\n362: \t\t\tcontinue\n363: \t\t}\n364: \t\tif tolerateNotFound {\n365: \t\t\tcontinue\n366: \t\t}\n367: \t\tif lastNotFoundErr != nil {\n368: \t\t\treturn lastNotFoundErr\n369: \t\t}\n370: \t\treturn errors.New(\"service control failed\")\n371: \t}\n372: \treturn nil\n373: }\n374: \n375: func (h *Handler) applyNodeProtocolChange(nodeID int64, httpVal, tlsVal, socksVal int) error {\n376: \t_, err := h.sendNodeCommand(nodeID, \"SetProtocol\", map[string]interface{}{\n377: \t\t\"http\":  httpVal,\n378: \t\t\"tls\":   tlsVal,\n379: \t\t\"socks\": socksVal,\n380: \t}, false, false)\n381: \treturn err\n382: }\n383: \n384: func (h *Handler) sendNodeCommand(nodeID int64, commandType string, data interface{}, tolerateExists bool, tolerateNotFound bool) (ws.CommandResult, error) {\n385: \treturn h.sendNodeCommandWithTimeout(nodeID, commandType, data, defaultNodeCommandTimeout, tolerateExists, tolerateNotFound)\n386: }\n387: \n388: func (h *Handler) sendNodeCommandWithTimeout(nodeID int64, commandType string, data interface{}, timeout time.Duration, tolerateExists bool, tolerateNotFound bool) (ws.CommandResult, error) {\n389: \tvar (\n390: \t\tresult ws.CommandResult\n391: \t\terr    error\n392: \t)\n393: \tif timeout <= 0 {\n394: \t\ttimeout = defaultNodeCommandTimeout\n395: \t}\n396: \n397: \tnode, nodeErr := h.getNodeRecord(nodeID)\n398: \tif nodeErr == nil && node != nil && node.IsRemote == 1 {\n399: \t\tresult, err = h.sendRemoteNodeCommandWithTimeout(node, commandType, data, timeout)\n400: \t} else {\n401: \t\tresult, err = h.wsServer.SendCommand(nodeID, commandType, data, timeout)\n402: \t}\n403: \tif err == nil {\n404: \t\treturn result, nil\n405: \t}\n406: \tmsg := strings.ToLower(strings.TrimSpace(err.Error()))\n407: \tif tolerateExists {\n408: \t\tif isAlreadyExistsMessage(msg) {\n409: \t\t\treturn result, nil\n410: \t\t}\n411: \t}\n412: \tif tolerateNotFound {\n413: \t\tif strings.Contains(msg, \"not found\") || strings.Contains(msg, \"不存在\") {\n414: \t\t\treturn result, nil\n415: \t\t}\n416: \t}\n417: \treturn result, err\n418: }\n419: \n420: func (h *Handler) sendRemoteNodeCommand(node *nodeRecord, commandType string, data interface{}) (ws.CommandResult, error) {\n421: \treturn h.sendRemoteNodeCommandWithTimeout(node, commandType, data, 0)\n422: }\n423: \n424: func (h *Handler) sendRemoteNodeCommandWithTimeout(node *nodeRecord, commandType string, data interface{}, timeout time.Duration) (ws.CommandResult, error) {\n425: \tif node == nil {\n426: \t\treturn ws.CommandResult{}, errors.New(\"节点不存在\")\n427: \t}\n428: \tremoteURL := strings.TrimSpace(node.RemoteURL)\n429: \tremoteToken := strings.TrimSpace(node.RemoteToken)\n430: \tif remoteURL == \"\" || remoteToken == \"\" {\n431: \t\treturn ws.CommandResult{}, errors.New(\"远程节点缺少共享配置\")\n432: \t}\n433: \n434: \tfc := client.NewFederationClient()\n435: \tif timeout > 0 {\n436: \t\tfc = client.NewFederationClientWithTimeout(timeout)\n437: \t}\n438: \tres, err := fc.Command(remoteURL, remoteToken, h.federationLocalDomain(), client.RuntimeNodeCommandRequest{\n439: \t\tCommandType: commandType,\n440: \t\tData:        data,\n441: \t})\n442: \tif err != nil {\n443: \t\treturn ws.CommandResult{}, err\n444: \t}\n445: \tif res == nil {\n446: \t\treturn ws.CommandResult{}, errors.New(\"远程节点未返回命令结果\")\n447: \t}\n448: \n449: \tresult := ws.CommandResult{\n450: \t\tType:    res.Type,\n451: \t\tSuccess: res.Success,\n452: \t\tMessage: res.Message,\n453: \t\tData:    res.Data,\n454: \t}\n455: \tif !result.Success {\n456: \t\tmsg := strings.TrimSpace(result.Message)\n457: \t\tif msg == \"\" {\n458: \t\t\tmsg = \"命令执行失败\"\n459: \t\t}\n460: \t\treturn result, errors.New(msg)\n461: \t}\n462: \treturn result, nil\n463: }\n464: \n465: func (h *Handler) diagnoseForwardRuntime(ctx context.Context, forward *forwardRecord) (map[string]interface{}, error) {\n466: \tif ctx == nil {\n467: \t\tctx = context.Background()\n468: \t}\n469: \tforwardName, workItems, err := h.prepareForwardDiagnosis(forward)\n470: \tif err != nil {\n471: \t\treturn nil, err\n472: \t}\n473: \n474: \tresults := h.runDiagnosisWorkItems(ctx, workItems, nil)\n475: \n476: \tpayload := map[string]interface{}{\n477: \t\t\"forwardName\": forwardName,\n478: \t\t\"timestamp\":   time.Now().UnixMilli(),\n479: \t\t\"results\":     results,\n480: \t}\n481: \treturn payload, nil\n482: }\n483: \n484: func (h *Handler) prepareForwardDiagnosis(forward *forwardRecord) (string, []diagnosisWorkItem, error) {\n485: \tif forward == nil {\n486: \t\treturn \"\", nil, errForwardNotFound\n487: \t}\n488: \ttargets, err := resolveDiagnosisTargets(forward.RemoteAddr)\n489: \tif err != nil {\n490: \t\treturn \"\", nil, err\n491: \t}\n492: \n493: \ttunnel, err := h.getTunnelRecord(forward.TunnelID)\n494: \tif err != nil {\n495: \t\treturn \"\", nil, err\n496: \t}\n497: \n498: \tchainRows, err := h.listChainNodesForTunnel(forward.TunnelID)\n499: \tif err != nil {\n500: \t\treturn \"\", nil, err\n501: \t}\n502: \tif len(chainRows) == 0 {\n503: \t\treturn \"\", nil, errors.New(\"隧道配置不完整\")\n504: \t}\n505: \n506: \tipPreference := h.repo.GetTunnelIPPreference(forward.TunnelID)\n507: \n508: \tinNodes, chainHops, outNodes := splitChainNodeGroups(chainRows)\n509: \tworkItems := make([]diagnosisWorkItem, 0, len(chainRows)*2+len(targets))\n510: \n511: \tswitch tunnel.Type {\n512: \tcase 1:\n513: \t\tfor _, inNode := range inNodes {\n514: \t\t\tfor _, target := range targets {\n515: \t\t\t\tdescription := fmt.Sprintf(\"入口(%s)->目标(%s)\", inNode.NodeName, target.Address)\n516: \t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n517: \t\t\t\t\tfromNodeID:  inNode.NodeID,\n518: \t\t\t\t\ttargetIP:    target.IP,\n519: \t\t\t\t\ttargetPort:  target.Port,\n520: \t\t\t\t\tdescription: description,\n521: \t\t\t\t\tmetadata: map[string]interface{}{\n522: \t\t\t\t\t\t\"fromChainType\": 1,\n523: \t\t\t\t\t},\n524: \t\t\t\t})\n525: \t\t\t}\n526: \t\t}\n527: \tcase 2:\n528: \t\tfor _, inNode := range inNodes {\n529: \t\t\tif len(chainHops) > 0 {\n530: \t\t\t\tfor _, firstNode := range chainHops[0] {\n531: \t\t\t\t\tdescription := fmt.Sprintf(\"入口(%s)->第1跳(%s)\", inNode.NodeName, firstNode.NodeName)\n532: \t\t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n533: \t\t\t\t\t\tfromNodeID:   inNode.NodeID,\n534: \t\t\t\t\t\ttoNode:       firstNode,\n535: \t\t\t\t\t\thasChainHop:  true,\n536: \t\t\t\t\t\tipPreference: ipPreference,\n537: \t\t\t\t\t\tdescription:  description,\n538: \t\t\t\t\t\tmetadata: map[string]interface{}{\n539: \t\t\t\t\t\t\t\"fromChainType\": 1,\n540: \t\t\t\t\t\t\t\"toChainType\":   2,\n541: \t\t\t\t\t\t\t\"toInx\":         firstNode.Inx,\n542: \t\t\t\t\t\t},\n543: \t\t\t\t\t})\n544: \t\t\t\t}\n545: \t\t\t} else {\n546: \t\t\t\tfor _, outNode := range outNodes {\n547: \t\t\t\t\tdescription := fmt.Sprintf(\"入口(%s)->出口(%s)\", inNode.NodeName, outNode.NodeName)\n548: \t\t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n549: \t\t\t\t\t\tfromNodeID:   inNode.NodeID,\n550: \t\t\t\t\t\ttoNode:       outNode,\n551: \t\t\t\t\t\thasChainHop:  true,\n552: \t\t\t\t\t\tipPreference: ipPreference,\n553: \t\t\t\t\t\tdescription:  description,\n554: \t\t\t\t\t\tmetadata: map[string]interface{}{\n555: \t\t\t\t\t\t\t\"fromChainType\": 1,\n556: \t\t\t\t\t\t\t\"toChainType\":   3,\n557: \t\t\t\t\t\t},\n558: \t\t\t\t\t})\n559: \t\t\t\t}\n560: \t\t\t}\n561: \t\t}\n562: \n563: \t\tfor i, hop := range chainHops {\n564: \t\t\tfor _, currentNode := range hop {\n565: \t\t\t\tif i+1 < len(chainHops) {\n566: \t\t\t\t\tfor _, nextNode := range chainHops[i+1] {\n567: \t\t\t\t\t\tdescription := fmt.Sprintf(\"第%d跳(%s)->第%d跳(%s)\", i+1, currentNode.NodeName, i+2, nextNode.NodeName)\n568: \t\t\t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n569: \t\t\t\t\t\t\tfromNodeID:   currentNode.NodeID,\n570: \t\t\t\t\t\t\ttoNode:       nextNode,\n571: \t\t\t\t\t\t\thasChainHop:  true,\n572: \t\t\t\t\t\t\tipPreference: ipPreference,\n573: \t\t\t\t\t\t\tdescription:  description,\n574: \t\t\t\t\t\t\tmetadata: map[string]interface{}{\n575: \t\t\t\t\t\t\t\t\"fromChainType\": 2,\n576: \t\t\t\t\t\t\t\t\"fromInx\":       currentNode.Inx,\n577: \t\t\t\t\t\t\t\t\"toChainType\":   2,\n578: \t\t\t\t\t\t\t\t\"toInx\":         nextNode.Inx,\n579: \t\t\t\t\t\t\t},\n580: \t\t\t\t\t\t})\n581: \t\t\t\t\t}\n582: \t\t\t\t} else {\n583: \t\t\t\t\tfor _, outNode := range outNodes {\n584: \t\t\t\t\t\tdescription := fmt.Sprintf(\"第%d跳(%s)->出口(%s)\", i+1, currentNode.NodeName, outNode.NodeName)\n585: \t\t\t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n586: \t\t\t\t\t\t\tfromNodeID:   currentNode.NodeID,\n587: \t\t\t\t\t\t\ttoNode:       outNode,\n588: \t\t\t\t\t\t\thasChainHop:  true,\n589: \t\t\t\t\t\t\tipPreference: ipPreference,\n590: \t\t\t\t\t\t\tdescription:  description,\n591: \t\t\t\t\t\t\tmetadata: map[string]interface{}{\n592: \t\t\t\t\t\t\t\t\"fromChainType\": 2,\n593: \t\t\t\t\t\t\t\t\"fromInx\":       currentNode.Inx,\n594: \t\t\t\t\t\t\t\t\"toChainType\":   3,\n595: \t\t\t\t\t\t\t},\n596: \t\t\t\t\t\t})\n597: \t\t\t\t\t}\n598: \t\t\t\t}\n599: \t\t\t}\n600: \t\t}\n601: \n602: \t\tfor _, outNode := range outNodes {\n603: \t\t\tfor _, target := range targets {\n604: \t\t\t\tdescription := fmt.Sprintf(\"出口(%s)->目标(%s)\", outNode.NodeName, target.Address)\n605: \t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n606: \t\t\t\t\tfromNodeID:  outNode.NodeID,\n607: \t\t\t\t\ttargetIP:    target.IP,\n608: \t\t\t\t\ttargetPort:  target.Port,\n609: \t\t\t\t\tdescription: description,\n610: \t\t\t\t\tmetadata: map[string]interface{}{\n611: \t\t\t\t\t\t\"fromChainType\": 3,\n612: \t\t\t\t\t},\n613: \t\t\t\t})\n614: \t\t\t}\n615: \t\t}\n616: \tdefault:\n617: \t\tfor _, inNode := range inNodes {\n618: \t\t\tfor _, target := range targets {\n619: \t\t\t\tdescription := fmt.Sprintf(\"入口(%s)->目标(%s)\", inNode.NodeName, target.Address)\n620: \t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n621: \t\t\t\t\tfromNodeID:  inNode.NodeID,\n622: \t\t\t\t\ttargetIP:    target.IP,\n623: \t\t\t\t\ttargetPort:  target.Port,\n624: \t\t\t\t\tdescription: description,\n625: \t\t\t\t\tmetadata: map[string]interface{}{\n626: \t\t\t\t\t\t\"fromChainType\": 1,\n627: \t\t\t\t\t},\n628: \t\t\t\t})\n629: \t\t\t}\n630: \t\t}\n631: \t}\n632: \n633: \treturn forward.Name, workItems, nil\n634: }\n635: \n636: func (h *Handler) diagnoseTunnelRuntime(ctx context.Context, tunnelID int64) (map[string]interface{}, error) {\n637: \tif ctx == nil {\n638: \t\tctx = context.Background()\n639: \t}\n640: \ttunnelName, tunnelType, workItems, err := h.prepareTunnelDiagnosis(tunnelID)\n641: \tif err != nil {\n642: \t\treturn nil, err\n643: \t}\n644: \n645: \tresults := h.runDiagnosisWorkItems(ctx, workItems, nil)\n646: \n647: \tpayload := map[string]interface{}{\n648: \t\t\"tunnelName\": tunnelName,\n649: \t\t\"tunnelType\": tunnelType,\n650: \t\t\"timestamp\":  time.Now().UnixMilli(),\n651: \t\t\"results\":    results,\n652: \t}\n653: \treturn payload, nil\n654: }\n655: \n656: func (h *Handler) prepareTunnelDiagnosis(tunnelID int64) (string, string, []diagnosisWorkItem, error) {\n657: \ttunnel, err := h.getTunnelRecord(tunnelID)\n658: \tif err != nil {\n659: \t\treturn \"\", \"\", nil, err\n660: \t}\n661: \n662: \ttunnelName, err := h.repo.GetTunnelName(tunnelID)\n663: \tif err != nil {\n664: \t\treturn \"\", \"\", nil, err\n665: \t}\n666: \tif tunnelName == \"\" {\n667: \t\treturn \"\", \"\", nil, errors.New(\"隧道不存在\")\n668: \t}\n669: \n670: \tchainRows, err := h.listChainNodesForTunnel(tunnelID)\n671: \tif err != nil {\n672: \t\treturn \"\", \"\", nil, err\n673: \t}\n674: \tif len(chainRows) == 0 {\n675: \t\treturn \"\", \"\", nil, errors.New(\"隧道配置不完整\")\n676: \t}\n677: \n678: \tipPreference := h.repo.GetTunnelIPPreference(tunnelID)\n679: \tinNodes, chainHops, outNodes := splitChainNodeGroups(chainRows)\n680: \tworkItems := make([]diagnosisWorkItem, 0, len(chainRows)*2)\n681: \n682: \tswitch tunnel.Type {\n683: \tcase 1:\n684: \t\tfor _, inNode := range inNodes {\n685: \t\t\tdescription := fmt.Sprintf(\"入口(%s)->外网\", inNode.NodeName)\n686: \t\t\tworkItems = append(workItems, diagnosisWorkItem{\n687: \t\t\t\tfromNodeID:  inNode.NodeID,\n688: \t\t\t\ttargetIP:    \"www.bing.com\",\n689: \t\t\t\ttargetPort:  443,\n690: \t\t\t\tdescription: description,\n691: \t\t\t\tmetadata: map[string]interface{}{\n692: \t\t\t\t\t\"fromChainType\": 1,\n693: \t\t\t\t},\n694: \t\t\t})\n695: \t\t}\n696: \tcase 2:\n697: \t\tfor _, inNode := range inNodes {\n698: \t\t\tif len(chainHops) > 0 {\n699: \t\t\t\tfor _, firstNode := range chainHops[0] {\n700: \t\t\t\t\tdescription := fmt.Sprintf(\"入口(%s)->第1跳(%s)\", inNode.NodeName, firstNode.NodeName)\n701: \t\t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n702: \t\t\t\t\t\tfromNodeID:   inNode.NodeID,\n703: \t\t\t\t\t\ttoNode:       firstNode,\n704: \t\t\t\t\t\thasChainHop:  true,\n705: \t\t\t\t\t\tipPreference: ipPreference,\n706: \t\t\t\t\t\tdescription:  description,\n707: \t\t\t\t\t\tmetadata: map[string]interface{}{\n708: \t\t\t\t\t\t\t\"fromChainType\": 1,\n709: \t\t\t\t\t\t\t\"toChainType\":   2,\n710: \t\t\t\t\t\t\t\"toInx\":         firstNode.Inx,\n711: \t\t\t\t\t\t},\n712: \t\t\t\t\t})\n713: \t\t\t\t}\n714: \t\t\t} else {\n715: \t\t\t\tfor _, outNode := range outNodes {\n716: \t\t\t\t\tdescription := fmt.Sprintf(\"入口(%s)->出口(%s)\", inNode.NodeName, outNode.NodeName)\n717: \t\t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n718: \t\t\t\t\t\tfromNodeID:   inNode.NodeID,\n719: \t\t\t\t\t\ttoNode:       outNode,\n720: \t\t\t\t\t\thasChainHop:  true,\n721: \t\t\t\t\t\tipPreference: ipPreference,\n722: \t\t\t\t\t\tdescription:  description,\n723: \t\t\t\t\t\tmetadata: map[string]interface{}{\n724: \t\t\t\t\t\t\t\"fromChainType\": 1,\n725: \t\t\t\t\t\t\t\"toChainType\":   3,\n726: \t\t\t\t\t\t},\n727: \t\t\t\t\t})\n728: \t\t\t\t}\n729: \t\t\t}\n730: \t\t}\n731: \n732: \t\tfor i, hop := range chainHops {\n733: \t\t\tfor _, currentNode := range hop {\n734: \t\t\t\tif i+1 < len(chainHops) {\n735: \t\t\t\t\tfor _, nextNode := range chainHops[i+1] {\n736: \t\t\t\t\t\tdescription := fmt.Sprintf(\"第%d跳(%s)->第%d跳(%s)\", i+1, currentNode.NodeName, i+2, nextNode.NodeName)\n737: \t\t\t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n738: \t\t\t\t\t\t\tfromNodeID:   currentNode.NodeID,\n739: \t\t\t\t\t\t\ttoNode:       nextNode,\n740: \t\t\t\t\t\t\thasChainHop:  true,\n741: \t\t\t\t\t\t\tipPreference: ipPreference,\n742: \t\t\t\t\t\t\tdescription:  description,\n743: \t\t\t\t\t\t\tmetadata: map[string]interface{}{\n744: \t\t\t\t\t\t\t\t\"fromChainType\": 2,\n745: \t\t\t\t\t\t\t\t\"fromInx\":       currentNode.Inx,\n746: \t\t\t\t\t\t\t\t\"toChainType\":   2,\n747: \t\t\t\t\t\t\t\t\"toInx\":         nextNode.Inx,\n748: \t\t\t\t\t\t\t},\n749: \t\t\t\t\t\t})\n750: \t\t\t\t\t}\n751: \t\t\t\t} else {\n752: \t\t\t\t\tfor _, outNode := range outNodes {\n753: \t\t\t\t\t\tdescription := fmt.Sprintf(\"第%d跳(%s)->出口(%s)\", i+1, currentNode.NodeName, outNode.NodeName)\n754: \t\t\t\t\t\tworkItems = append(workItems, diagnosisWorkItem{\n755: \t\t\t\t\t\t\tfromNodeID:   currentNode.NodeID,\n756: \t\t\t\t\t\t\ttoNode:       outNode,\n757: \t\t\t\t\t\t\thasChainHop:  true,\n758: \t\t\t\t\t\t\tipPreference: ipPreference,\n759: \t\t\t\t\t\t\tdescription:  description,\n760: \t\t\t\t\t\t\tmetadata: map[string]interface{}{\n761: \t\t\t\t\t\t\t\t\"fromChainType\": 2,\n762: \t\t\t\t\t\t\t\t\"fromInx\":       currentNode.Inx,\n763: \t\t\t\t\t\t\t\t\"toChainType\":   3,\n764: \t\t\t\t\t\t\t},\n765: \t\t\t\t\t\t})\n766: \t\t\t\t\t}\n767: \t\t\t\t}\n768: \t\t\t}\n769: \t\t}\n770: \n771: \t\tfor _, outNode := range outNodes {\n772: \t\t\tdescription := fmt.Sprintf(\"出口(%s)->外网\", outNode.NodeName)\n773: \t\t\tworkItems = append(workItems, diagnosisWorkItem{\n774: \t\t\t\tfromNodeID:  outNode.NodeID,\n775: \t\t\t\ttargetIP:    \"www.bing.com\",\n776: \t\t\t\ttargetPort:  443,\n777: \t\t\t\tdescription: description,\n778: \t\t\t\tmetadata: map[string]interface{}{\n779: \t\t\t\t\t\"fromChainType\": 3,\n780: \t\t\t\t},\n781: \t\t\t})\n782: \t\t}\n783: \tdefault:\n784: \t\tfor _, inNode := range inNodes {\n785: \t\t\tdescription := fmt.Sprintf(\"入口(%s)->外网\", inNode.NodeName)\n786: \t\t\tworkItems = append(workItems, diagnosisWorkItem{\n787: \t\t\t\tfromNodeID:  inNode.NodeID,\n788: \t\t\t\ttargetIP:    \"www.bing.com\",\n789: \t\t\t\ttargetPort:  443,\n790: \t\t\t\tdescription: description,\n791: \t\t\t\tmetadata: map[string]interface{}{\n792: \t\t\t\t\t\"fromChainType\": 1,\n793: \t\t\t\t},\n794: \t\t\t})\n795: \t\t}\n796: \t}\n797: \n798: \ttunnelType := map[bool]string{true: \"端口转发\", false: \"隧道转发\"}[tunnel.Type == 1]\n799: \treturn tunnelName, tunnelType, workItems, nil\n800: }\n801: \n802: func splitChainNodeGroups(rows []chainNodeRecord) ([]chainNodeRecord, [][]chainNodeRecord, []chainNodeRecord) {\n803: \tinNodes := make([]chainNodeRecord, 0)\n804: \toutNodes := make([]chainNodeRecord, 0)\n805: \tchainByInx := map[int64][]chainNodeRecord{}\n806: \thopOrder := make([]int64, 0)\n807: \n808: \tfor _, row := range rows {\n809: \t\tswitch row.ChainType {\n810: \t\tcase 1:\n811: \t\t\tinNodes = append(inNodes, row)\n812: \t\tcase 2:\n813: \t\t\tif _, ok := chainByInx[row.Inx]; !ok {\n814: \t\t\t\thopOrder = append(hopOrder, row.Inx)\n815: \t\t\t}\n816: \t\t\tchainByInx[row.Inx] = append(chainByInx[row.Inx], row)\n817: \t\tcase 3:\n818: \t\t\toutNodes = append(outNodes, row)\n819: \t\t}\n820: \t}\n821: \n822: \tsort.Slice(hopOrder, func(i, j int) bool { return hopOrder[i] < hopOrder[j] })\n823: \tchainHops := make([][]chainNodeRecord, 0, len(hopOrder))\n824: \tfor _, inx := range hopOrder {\n825: \t\tchainHops = append(chainHops, chainByInx[inx])\n826: \t}\n827: \n828: \treturn inNodes, chainHops, outNodes\n829: }\n830: \n831: func resolveDiagnosisTargets(remoteAddr string) ([]diagnosisTarget, error) {\n832: \trawTargets := splitRemoteTargets(remoteAddr)\n833: \tif len(rawTargets) == 0 {\n834: \t\treturn nil, errors.New(\"目标地址不能为空\")\n835: \t}\n836: \n837: \ttargets := make([]diagnosisTarget, 0, len(rawTargets))\n838: \tfor _, raw := range rawTargets {\n839: \t\tip, port, err := parseTargetAddress(raw)\n840: \t\tif err != nil {\n841: \t\t\tcontinue\n842: \t\t}\n843: \t\ttargets = append(targets, diagnosisTarget{Address: raw, IP: ip, Port: port})\n844: \t}\n845: \tif len(targets) == 0 {\n846: \t\treturn nil, errors.New(\"目标地址格式错误\")\n847: \t}\n848: \treturn targets, nil\n849: }\n850: \n851: func diagnosisContextMessage(ctx context.Context) string {\n852: \tif ctx == nil {\n853: \t\treturn diagnosisRequestTimeoutMsg\n854: \t}\n855: \tswitch ctx.Err() {\n856: \tcase context.DeadlineExceeded:\n857: \t\treturn diagnosisRequestTimeoutMsg\n858: \tcase context.Canceled:\n859: \t\treturn \"诊断已取消\"\n860: \tdefault:\n861: \t\treturn diagnosisRequestTimeoutMsg\n862: \t}\n863: }\n864: \n865: func diagnosisExecOptionsFromContext(ctx context.Context) diagnosisExecOptions {\n866: \ttimeout := diagnosisCommandTimeout\n867: \tif ctx != nil {\n868: \t\tif deadline, ok := ctx.Deadline(); ok {\n869: \t\t\tremaining := time.Until(deadline)\n870: \t\t\tif remaining <= 0 {\n871: \t\t\t\tremaining = 100 * time.Millisecond\n872: \t\t\t}\n873: \t\t\tif remaining < timeout {\n874: \t\t\t\ttimeout = remaining\n875: \t\t\t}\n876: \t\t}\n877: \t}\n878: \tif timeout <= 0 {\n879: \t\ttimeout = 100 * time.Millisecond\n880: \t}\n881: \tpingTimeoutMS := int(timeout / time.Millisecond)\n882: \tif pingTimeoutMS <= 0 {\n883: \t\tpingTimeoutMS = 100\n884: \t}\n885: \treturn diagnosisExecOptions{\n886: \t\tcommandTimeout: timeout,\n887: \t\tpingTimeoutMS:  pingTimeoutMS,\n888: \t\ttimeoutMessage: diagnosisContextMessage(ctx),\n889: \t}\n890: }\n891: \n892: func newDiagnosisTimeoutItem(workItem diagnosisWorkItem, message string) map[string]interface{} {\n893: \ttargetPort := workItem.targetPort\n894: \tif targetPort <= 0 {\n895: \t\ttargetPort = workItem.toNode.Port\n896: \t}\n897: \titem := newDiagnosisResultItem(workItem.fromNodeID, workItem.targetIP, targetPort, workItem.description, workItem.metadata)\n898: \titem[\"success\"] = false\n899: \tif strings.TrimSpace(message) == \"\" {\n900: \t\tmessage = diagnosisCommandTimeoutMsg\n901: \t}\n902: \titem[\"message\"] = message\n903: \treturn item\n904: }\n905: \n906: func (h *Handler) executeDiagnosisWorkItem(workItem diagnosisWorkItem, options diagnosisExecOptions) map[string]interface{} {\n907: \tsingle := make([]map[string]interface{}, 0, 1)\n908: \tnodeCache := map[int64]*nodeRecord{}\n909: \tif workItem.hasChainHop {\n910: \t\th.appendChainHopDiagnosis(&single, nodeCache, workItem.fromNodeID, workItem.toNode, workItem.description, workItem.metadata, workItem.ipPreference, options)\n911: \t} else {\n912: \t\th.appendPathDiagnosis(&single, nodeCache, workItem.fromNodeID, workItem.targetIP, workItem.targetPort, workItem.description, workItem.metadata, options)\n913: \t}\n914: \n915: \tif len(single) == 0 {\n916: \t\treturn newDiagnosisTimeoutItem(workItem, \"诊断任务未返回结果\")\n917: \t}\n918: \treturn single[0]\n919: }\n920: \n921: func (h *Handler) runDiagnosisWorkItems(ctx context.Context, workItems []diagnosisWorkItem, emitter diagnosisItemEmitter) []map[string]interface{} {\n922: \tif ctx == nil {\n923: \t\tctx = context.Background()\n924: \t}\n925: \tresults := make([]map[string]interface{}, len(workItems))\n926: \tif len(workItems) == 0 {\n927: \t\treturn results\n928: \t}\n929: \n930: \tworkerLimit := diagnosisMaxConcurrency\n931: \tif workerLimit < 1 {\n932: \t\tworkerLimit = 1\n933: \t}\n934: \tif workerLimit > len(workItems) {\n935: \t\tworkerLimit = len(workItems)\n936: \t}\n937: \n938: \ttype diagnosisWorkResult struct {\n939: \t\tindex int