002: }\n1003: \n1004: func (h *Handler) cachedNode(nodeCache map[int64]*nodeRecord, nodeID int64) (*nodeRecord, error) {\n1005: \tif node, ok := nodeCache[nodeID]; ok {\n1006: \t\treturn node, nil\n1007: \t}\n1008: \tnode, err := h.getNodeRecord(nodeID)\n1009: \tif err != nil {\n1010: \t\treturn nil, err\n1011: \t}\n1012: \tnodeCache[nodeID] = node\n1013: \treturn node, nil\n1014: }\n1015: \n1016: func newDiagnosisResultItem(fromNodeID int64, targetIP string, targetPort int, description string, metadata map[string]interface{}) map[string]interface{} {\n1017: \titem := map[string]interface{}{\n1018: \t\t\"nodeName\":    fmt.Sprintf(\"node_%d\", fromNodeID),\n1019: \t\t\"nodeId\":      strconv.FormatInt(fromNodeID, 10),\n1020: \t\t\"targetIp\":    targetIP,\n1021: \t\t\"targetPort\":  targetPort,\n1022: \t\t\"description\": description,\n1023: \t\t\"averageTime\": 0,\n1024: \t\t\"packetLoss\":  100,\n1025: \t}\n1026: \tfor k, v := range metadata {\n1027: \t\titem[k] = v\n1028: \t}\n1029: \treturn item\n1030: }\n1031: \n1032: func (h *Handler) appendFailedDiagnosis(results *[]map[string]interface{}, nodeCache map[int64]*nodeRecord, fromNodeID int64, targetIP string, targetPort int, description string, metadata map[string]interface{}, message string) {\n1033: \titem := newDiagnosisResultItem(fromNodeID, targetIP, targetPort, description, metadata)\n1034: \tif node, err := h.cachedNode(nodeCache, fromNodeID); err == nil {\n1035: \t\titem[\"nodeName\"] = node.Name\n1036: \t}\n1037: \tif strings.TrimSpace(message) == \"\" {\n1038: \t\tmessage = \"TCP连接失败\"\n1039: \t}\n1040: \titem[\"success\"] = false\n1041: \titem[\"message\"] = message\n1042: \t*results = append(*results, item)\n1043: }\n1044: \n1045: func (h *Handler) appendPathDiagnosis(results *[]map[string]interface{}, nodeCache map[int64]*nodeRecord, fromNodeID int64, targetIP string, targetPort int, description string, metadata map[string]interface{}, options diagnosisExecOptions) {\n1046: \titem := newDiagnosisResultItem(fromNodeID, targetIP, targetPort, description, metadata)\n1047: \n1048: \tfromNode, err := h.cachedNode(nodeCache, fromNodeID)\n1049: \tif err != nil {\n1050: \t\titem[\"success\"] = false\n1051: \t\titem[\"message\"] = err.Error()\n1052: \t\t*results = append(*results, item)\n1053: \t\treturn\n1054: \t}\n1055: \titem[\"nodeName\"] = fromNode.Name\n1056: \n1057: \tvar (\n1058: \t\tpingData map[string]interface{}\n1059: \t\tpingErr  error\n1060: \t)\n1061: \tif fromNode.IsRemote == 1 {\n1062: \t\tpingData, pingErr = h.tcpPingViaRemoteNode(fromNode, targetIP, targetPort, options)\n1063: \t} else {\n1064: \t\tpingData, pingErr = h.tcpPingViaNode(fromNodeID, targetIP, targetPort, options)\n1065: \t}\n1066: \tif pingErr != nil {\n1067: \t\titem[\"success\"] = false\n1068: \t\titem[\"message\"] = pingErr.Error()\n1069: \t\t*results = append(*results, item)\n1070: \t\treturn\n1071: \t}\n1072: \n1073: \tsuccess := asBool(pingData[\"success\"], false)\n1074: \titem[\"success\"] = success\n1075: \titem[\"averageTime\"] = asFloat(pingData[\"averageTime\"], 0)\n1076: \titem[\"packetLoss\"] = asFloat(pingData[\"packetLoss\"], 100)\n1077: \n1078: \tmessage := strings.TrimSpace(asString(pingData[\"message\"]))\n1079: \tif success {\n1080: \t\tif message == \"\" {\n1081: \t\t\tmessage = \"TCP连接成功\"\n1082: \t\t}\n1083: \t} else {\n1084: \t\tif message == \"\" {\n1085: \t\t\tmessage = strings.TrimSpace(asString(pingData[\"errorMessage\"]))\n1086: \t\t}\n1087: \t\tif message == \"\" {\n1088: \t\t\tmessage = \"TCP连接失败\"\n1089: \t\t}\n1090: \t}\n1091: \titem[\"message\"] = message\n1092: \t*results = append(*results, item)\n1093: }\n1094: \n1095: func (h *Handler) appendChainHopDiagnosis(results *[]map[string]interface{}, nodeCache map[int64]*nodeRecord, fromNodeID int64, toNode chainNodeRecord, description string, metadata map[string]interface{}, ipPreference string, options diagnosisExecOptions) {\n1096: \tfromNode, _ := h.cachedNode(nodeCache, fromNodeID)\n1097: \ttargetNode, err := h.cachedNode(nodeCache, toNode.NodeID)\n1098: \tif err != nil {\n1099: \t\th.appendFailedDiagnosis(results, nodeCache, fromNodeID, \"\", 0, description, metadata, err.Error())\n1100: \t\treturn\n1101: \t}\n1102: \ttargetIP, targetPort, err := resolveChainProbeTarget(fromNode, targetNode, toNode.Port, ipPreference)\n1103: \tif err != nil {\n1104: \t\th.appendFailedDiagnosis(results, nodeCache, fromNodeID, strings.Trim(strings.TrimSpace(targetNode.ServerIP), \"[]\"), toNode.Port, description, metadata, err.Error())\n1105: \t\treturn\n1106: \t}\n1107: \th.appendPathDiagnosis(results, nodeCache, fromNodeID, targetIP, targetPort, description, metadata, options)\n1108: }\n1109: \n1110: func resolveChainProbeTarget(fromNode, targetNode *nodeRecord, preferredPort int, ipPreference string) (string, int, error) {\n1111: \tif targetNode == nil {\n1112: \t\treturn \"\", 0, errors.New(\"目标节点不存在\")\n1113: \t}\n1114: \thost, err := selectTunnelDialHost(fromNode, targetNode, ipPreference)\n1115: \tif err != nil {\n1116: \t\thost = strings.Trim(strings.TrimSpace(targetNode.ServerIP), \"[]\")\n1117: \t}\n1118: \tif host == \"\" {\n1119: \t\treturn \"\", 0, errors.New(\"目标节点地址为空\")\n1120: \t}\n1121: \tport := preferredPort\n1122: \tif port <= 0 {\n1123: \t\tport = firstPortFromRange(targetNode.PortRange)\n1124: \t}\n1125: \tif port <= 0 {\n1126: \t\tport = 443\n1127: \t}\n1128: \treturn host, port, nil\n1129: }\n1130: \n1131: func firstPortFromRange(portRange string) int {\n1132: \tportRange = strings.TrimSpace(portRange)\n1133: \tif portRange == \"\" {\n1134: \t\treturn 0\n1135: \t}\n1136: \tfirst := strings.Split(portRange, \",\")[0]\n1137: \tfirst = strings.TrimSpace(first)\n1138: \tif strings.Contains(first, \"-\") {\n1139: \t\tparts := strings.SplitN(first, \"-\", 2)\n1140: \t\tif len(parts) != 2 {\n1141: \t\t\treturn 0\n1142: \t\t}\n1143: \t\tp, err := strconv.Atoi(strings.TrimSpace(parts[0]))\n1144: \t\tif err != nil || p <= 0 {\n1145: \t\t\treturn 0\n1146: \t\t}\n1147: \t\treturn p\n1148: \t}\n1149: \tp, err := strconv.Atoi(first)\n1150: \tif err != nil || p <= 0 {\n1151: \t\treturn 0\n1152: \t}\n1153: \treturn p\n1154: }\n1155: \n1156: func (h *Handler) listChainNodesForTunnel(tunnelID int64) ([]chainNodeRecord, error) {\n1157: \treturn h.repo.ListChainNodesForTunnel(tunnelID)\n1158: }\n1159: \n1160: func (h *Handler) tcpPingViaNode(nodeID int64, ip string, port int, options diagnosisExecOptions) (map[string]interface{}, error) {\n1161: \tif options.commandTimeout <= 0 {\n1162: \t\toptions.commandTimeout = diagnosisCommandTimeout\n1163: \t}\n1164: \tif options.pingTimeoutMS <= 0 {\n1165: \t\toptions.pingTimeoutMS = int(diagnosisCommandTimeout / time.Millisecond)\n1166: \t}\n1167: \tres, err := h.sendNodeCommandWithTimeout(nodeID, \"TcpPing\", map[string]interface{}{\n1168: \t\t\"ip\":      ip,\n1169: \t\t\"port\":    port,\n1170: \t\t\"count\":   4,\n1171: \t\t\"timeout\": options.pingTimeoutMS,\n1172: \t}, options.commandTimeout, false, false)\n1173: \tif err != nil {\n1174: \t\treturn nil, err\n1175: \t}\n1176: \tif res.Data == nil {\n1177: \t\treturn nil, errors.New(\"节点未返回诊断数据\")\n1178: \t}\n1179: \treturn res.Data, nil\n1180: }\n1181: \n1182: func (h *Handler) tcpPingViaRemoteNode(node *nodeRecord, ip string, port int, options diagnosisExecOptions) (map[string]interface{}, error) {\n1183: \tif node == nil {\n1184: \t\treturn nil, errors.New(\"节点不存在\")\n1185: \t}\n1186: \tremoteURL := strings.TrimSpace(node.RemoteURL)\n1187: \tremoteToken := strings.TrimSpace(node.RemoteToken)\n1188: \tif remoteURL == \"\" || remoteToken == \"\" {\n1189: \t\treturn nil, errors.New(\"远程节点缺少共享配置\")\n1190: \t}\n1191: \tif options.commandTimeout <= 0 {\n1192: \t\toptions.commandTimeout = diagnosisCommandTimeout\n1193: \t}\n1194: \tif options.pingTimeoutMS <= 0 {\n1195: \t\toptions.pingTimeoutMS = int(diagnosisCommandTimeout / time.Millisecond)\n1196: \t}\n1197: \n1198: \tfc := client.NewFederationClientWithTimeout(options.commandTimeout)\n1199: \treturn fc.Diagnose(remoteURL, remoteToken, h.federationLocalDomain(), client.RuntimeDiagnoseRequest{\n1200: \t\tIP:      strings.TrimSpace(ip),\n1201: \t\tPort:    port,\n1202: \t\tCount:   4,\n1203: \t\tTimeout: options.pingTimeoutMS,\n1204: \t})\n1205: }\n1206: \n1207: func splitRemoteTargets(remoteAddr string) []string {\n1208: \tparts := strings.Split(remoteAddr, \",\")\n1209: \tout := make([]string, 0, len(parts))\n1210: \tfor _, part := range parts {\n1211: \t\tpart = strings.TrimSpace(part)\n1212: \t\tif part == \"\" {\n1213: \t\t\tcontinue\n1214: \t\t}\n1215: \t\tout = append(out, processServerAddress(part))\n1216: \t}\n1217: \treturn out\n1218: }\n1219: \n1220: func parseTargetAddress(addr string) (string, int, error) {\n1221: \taddr = strings.TrimSpace(addr)\n1222: \tif addr == \"\" {\n1223: \t\treturn \"\", 0, errors.New(\"empty address\")\n1224: \t}\n1225: \thost, portStr, err := net.SplitHostPort(addr)\n1226: \tif err != nil {\n1227: \t\tidx := strings.LastIndex(addr, \":\")\n1228: \t\tif idx <= 0 || idx >= len(addr)-1 {\n1229: \t\t\treturn \"\", 0, err\n1230: \t\t}\n1231: \t\thost = strings.TrimSpace(addr[:idx])\n1232: \t\tportStr = strings.TrimSpace(addr[idx+1:])\n1233: \t}\n1234: \tport, err := strconv.Atoi(strings.TrimSpace(portStr))\n1235: \tif err != nil || port <= 0 || port > 65535 {\n1236: \t\treturn \"\", 0, errors.New(\"invalid port\")\n1237: \t}\n1238: \thost = strings.Trim(strings.TrimSpace(host), \"[]\")\n1239: \tif host == \"\" {\n1240: \t\treturn \"\", 0, errors.New(\"invalid host\")\n1241: \t}\n1242: \treturn host, port, nil\n1243: }\n1244: \n1245: func buildForwardServiceBase(forwardID, userID, userTunnelID int64) string {\n1246: \treturn fmt.Sprintf(\"%d_%d_%d\", forwardID, userID, userTunnelID)\n1247: }\n1248: \n1249: func buildForwardServiceBaseCandidates(forwardID, userID, preferredUserTunnelID int64, userTunnelIDs []int64) []string {\n1250: \torderedIDs := make([]int64, 0, len(userTunnelIDs)+2)\n1251: \tseen := make(map[int64]str