func (r *Repository) CreateForwardTx(..., entryNodeIDs []int64, port int, ...) (int64, error) {
    // 创建 forward 记录
    // 为每个入口节点创建 forward_port 记录
    for _, nodeID := range entryNodeIDs {
        fp := model.ForwardPort{
            ForwardID: forwardID,
            NodeID:    nodeID,    // 入口节点ID
            Port:      port,      // 入口端口
        }
        tx.Create(&fp)
    }
}
